parameters.jsCode:
let links;
try { links = JSON.parse(($input.first().json.message?.content||'[]').replace(/```json|```/g,'').trim()); if (!Array.isArray(links)) links = []; } catch { links = []; }
const strong = links.filter(l=>l.connection_score>=7);
return [{ json: { date: new Date().toISOString().slice(0,10), total_links: links.length, strong_links: strong.length, links, strong } }];

